  ('elementary-f29af906-moex-00561', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地徵收條例規定，徵收土地之殘餘部分面積過小或形勢不整，致不能為相當之使用者，土地所 有權人若申請一併徵收，應於何時提出申請？', '["徵收公告之日起30日內", "徵收公告之日起3個月內", "徵收公告之日起6個月內", "徵收公告之日起1年內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
