  ('elementary-f29af906-moex-00563', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '出租耕地經依法編為建築用地者，出租人為收回自行建築或出售作為建築使用時，得終止租約。終 止耕地租約時，應由土地所有權人以書面向直轄市或縣（市）政府提出申請，經審核其已與承租人 協議成立者，應准終止耕地租約。有關前述規定，下列何者錯誤？', '["地方政府准予終止之決定，性質屬於形成私法效果的行政處分", "地方政府准予終止之決定，性質屬於單方行政行為的行政處分", "出租人與承租人之間有關終止租約的協議，性質屬於行政契約", "出租人與承租人之間有關終止租約的協議，性質屬於私法契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00564', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '區段徵收範圍內土地，經規劃整理後，主管機關將抵價地發交給被徵收土地所有權人領回，其性質 屬下列何者？', '["買賣性質", "契約性質", "公法行為性質", "交換性質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00565', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依國土計畫法規定，目的事業主管機關為執行國土復育促進地區之復育計畫，必要時，得依法價購、 徵收區內私有土地及合法土地改良物。有關前述土地之取得，下列敘述何者正確？', '["依法價購所訂定之契約，其性質應屬單務契約", "依法價購所訂定之契約，其性質應屬和解契約", "條文既規定得依法徵收，故得裁量直接徵收", "其取得仍應依土地徵收條例規定，採價購優先"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
