  ('elementary-f29af906-moex-00567', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依國土計畫法規定，符合國土功能分區及其分類之使用原則下，人民得從事「一定規模以上或性質 特殊之土地使用」，其認定標準由中央主管機關定之。下列敘述何者正確？', '["認定標準的性質應屬於法規命令", "認定標準的性質應屬於行政規則", "認定標準得委由地方政府各自訂定", "依國土計畫法規定，為因地制宜該認定標準得由地方政府斟酌情形予以放寬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
